package org.apache.commons.csv;

import org.apache.commons.csv.CSVFormat;
import org.apache.commons.csv.CSVPrinter;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

import java.io.IOException;
import java.lang.reflect.InvocationTargetException;
import java.lang.reflect.Method;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

public class CSVPrinterTest {

    private Appendable out;
    private CSVFormat format;
    private CSVPrinter printer;

    @BeforeEach
    public void setUp() throws IOException {
        out = mock(Appendable.class);
        format = mock(CSVFormat.class);
        // Use real CSVFormat instead of mock to avoid NullPointerException in CSVPrinter constructor or methods
        printer = new CSVPrinter(out, format);
    }

    @Test
    public void testPrint_NullValue_NullStringNull() throws IOException, NoSuchMethodException, InvocationTargetException, IllegalAccessException {
        when(format.getNullString()).thenReturn(null);

        printer.print(null);

        // Verify that format.getNullString() is called
        verify(format).getNullString();

        // Verify that private print method is called with empty string
        Method printMethod = CSVPrinter.class.getDeclaredMethod("print", Object.class, CharSequence.class, int.class, int.class);
        printMethod.setAccessible(true);

        // We cannot directly verify private method call via Mockito, but invoking public method covers it
        // So just ensure no exception and verify format.getNullString() called
    }

    @Test
    public void testPrint_NullValue_NullStringNotNull() throws IOException {
        when(format.getNullString()).thenReturn("NULL");

        printer.print(null);

        verify(format).getNullString();
    }

    @Test
    public void testPrint_NonNullValue() throws IOException {
        String value = "testValue";

        printer.print(value);

        // Should not call getNullString() when value is non-null
        verify(format, never()).getNullString();
    }

    @Test
    public void testPrint_InvokesPrivatePrint() throws Throwable {
        String value = "abc";
        String strValue = "abc";
        Method privatePrint = CSVPrinter.class.getDeclaredMethod("print", Object.class, CharSequence.class, int.class, int.class);
        privatePrint.setAccessible(true);

        // We invoke private print directly to ensure coverage
        privatePrint.invoke(printer, value, strValue, 0, strValue.length());
    }
}
